// ── Map TeleCRM payload → our format (shape-agnostic) ─────────────
// TeleCRM's 'Forge App Onboarding' template uses vars like lead.name,
// lead.email, lead.phone_number, body.payment_status, body.product, body.edition.
// We don't know if they arrive flat, dotted ('lead.name'), or nested
// ({lead:{name}}), so we FLATTEN everything and look up by the last key segment.
const root = $input.first().json.body || $input.first().json;
console.log('TeleCRM payload:', JSON.stringify(root));

const flat = {};
const add = (k, v) => { if (v !== null && v !== undefined && typeof v !== 'object') flat[String(k).toLowerCase()] = v; };
for (const [k, v] of Object.entries(root || {})) {
  if (v && typeof v === 'object' && !Array.isArray(v)) {
    for (const [k2, v2] of Object.entries(v)) add(k2.includes('.') ? k2.split('.').pop() : k2, v2);
  } else {
    add(k.includes('.') ? k.split('.').pop() : k, v);
  }
}
const g = (...keys) => { for (const k of keys) { const val = flat[k.toLowerCase()]; if (val !== undefined && String(val).trim() !== '') return String(val).trim(); } return ''; };

const email        = g('email_1', 'email', 'lead_email', 'mail').toLowerCase();
// Normalise the name → Title Case so 'ABHISHAKE KUMAR'/'abhishake kumar' → 'Abhishake Kumar'.
// This keeps the displayed name AND the Firstname@Forge! password clean & consistent.
const titleCase = (s) => s.replace(/\s+/g, ' ').trim().split(' ').map((w) => w ? w.charAt(0).toUpperCase() + w.slice(1).toLowerCase() : '').join(' ');
const full_name    = titleCase(g('name', 'full_name', 'lead_name'));
const phone        = g('phone', 'phone_number', 'mobile');
const edition_name = g('edition', 'edition_name');
const product      = (g('product') || 'FFM').toUpperCase();
const amount       = parseInt(g('amount').replace(/[^0-9]/g, ''), 10) || 0;
const raw_status   = g('payment_status', 'status', 'tag').toLowerCase();

const BALANCE_PAID  = ['balance paid', 'balance_paid', 'full paid', 'completed', 'balance', 'full'];
const CONFIRMED_15K = ['confirmed_15k', '15k', 'deposit', 'confirmed', 'slot', 'advance', 'token', 'booking'];
const DEFERRED      = ['defer', 'waitlist', 'postpone', 'hold'];

// Classify by AMOUNT first (if sent), then by the status word.
let payment_status = null;
if      (amount >= 50000) payment_status = 'BALANCE_PAID';
else if (amount >= 15000) payment_status = 'CONFIRMED_15K';
else if (BALANCE_PAID.some(v  => raw_status.includes(v)))  payment_status = 'BALANCE_PAID';
else if (CONFIRMED_15K.some(v => raw_status.includes(v)))  payment_status = 'CONFIRMED_15K';
else if (DEFERRED.some(v      => raw_status.includes(v)))  payment_status = 'DEFERRED';

if (!email || !email.includes('@')) { console.log('No valid email in payload'); return []; }
if (!payment_status) { console.log('Unrecognised payment — amount:', amount, 'status:', raw_status); return []; }

const PRODUCT_COHORT = { FFM: 'FFM', FC: 'FC', FW: 'FW', FAI: 'FAI' };
const cohort_type = PRODUCT_COHORT[product] || 'FFM';

return [{ json: {
  student_id:   email,
  email,
  full_name,
  phone:        phone        || undefined,
  product,
  payment_status,
  cohort_type,
  edition_name: edition_name || undefined,
  _onboardable: payment_status === 'CONFIRMED_15K' || payment_status === 'BALANCE_PAID'
}}];

// Build a log row combining the original student data + onboarding API response.
return $input.all().map(item => {
  const resp = item.json;
  const orig = $('Map TeleCRM Fields').item.json;
  return { json: {
    'Timestamp': new Date().toISOString().replace('T', ' ').slice(0, 19),
    'Email':     orig.email        || '',
    'Name':      orig.full_name    || '',
    'Edition':   orig.edition_name || '',
    'Payment':   orig.payment_status || '',
    'Product':   orig.product      || '',
    'Action':    'Onboarding (TeleCRM)',
    'Status':    resp.status       || 'unknown',
    'Details':   resp.message      || resp.error || JSON.stringify(resp).slice(0, 300)
  }};
});

// Build a log row for payment sync events.
return $input.all().map(item => {
  const orig = $('Map TeleCRM Fields').item.json;
  return { json: {
    'Timestamp': new Date().toISOString().replace('T', ' ').slice(0, 19),
    'Email':     orig.email        || '',
    'Name':      orig.full_name    || '',
    'Edition':   orig.edition_name || '',
    'Payment':   orig.payment_status || '',
    'Product':   orig.product      || '',
    'Action':    'Payment Sync (TeleCRM)',
    'Status':    'synced',
    'Details':   `${orig.payment_status} → unlock_level: ${orig.payment_status === 'BALANCE_PAID' ? 'FULL' : 'PREVIEW'}`
  }};
});
